import { useRef } from 'react';
import {
  motion,
  useScroll,
  useTransform,
  useSpring,
  useMotionValue,
  useMotionValueEvent,
} from 'framer-motion';

// Animated GIF previews (animated WebP, one per service)
const VIDEO_GIFS = {
  '01': 'data:image/webp;base64,',
  '02': 'data:image/webp;base64,',
  '03': 'data:image/webp;base64,',
  '04': 'data:image/webp;base64,',
  '05': 'data:image/webp;base64,',
  '06': 'data:image/webp;base64,'
};
const services = [
  { num: '01', title: 'Short Form Editing',    desc: 'Reels, TikToks, and YouTube Shorts crafted for maximum retention and virality.',           tags: ['Reels', 'TikTok', 'Shorts', 'Viral'], icon: '\u25B6' },
  { num: '02', title: 'YouTube Editing',       desc: 'Long-form content with strategic pacing, chapters, and engagement hooks that keep viewers watching.', tags: ['Long-form', 'Thumbnails', 'SEO'], icon: '\u25C6' },
  { num: '03', title: 'Commercial Production', desc: 'Brand videos and product commercials that convert viewers into customers.',                tags: ['Brand', 'Product', 'Commercial'],     icon: '\u2726' },
  { num: '04', title: 'Real Estate Videos',    desc: 'Luxury property showcases that sell the dream and close faster.',                          tags: ['Property', 'Luxury', 'Drone'],        icon: '\u2B21' },
  { num: '05', title: 'Wedding Films',         desc: 'Emotional, cinematic wedding films that preserve your most important day forever.',       tags: ['Wedding', 'Cinematic', 'Emotional'],  icon: '\u274B' },
  { num: '06', title: 'Motion Graphics',       desc: 'Animated logos, intros, and full brand motion packages that make you stand out.',          tags: ['Animation', 'Logo', 'Brand Motion'],  icon: '\u25C8' },
];

const HEADLINE = ['What', 'I', 'Create'];

function ServiceCard({ s, i, p }) {
  const start = 0.32 + i * 0.10;
  const cardScale   = useTransform(p, [start, start + 0.08, start + 0.16], [0.94, 1.03, 0.94]);
  const cardOpacity = useTransform(p, [start - 0.05, start + 0.08, start + 0.22], [0.55, 1, 0.55]);

  return (
    <motion.article
      style={{
        flex: '0 0 auto',
        width: 'clamp(260px, 26vw, 380px)',
        height: '78vh',
        borderRadius: 28,
        padding: '0',
        background: 'linear-gradient(160deg, rgba(30,40,55,0.85), rgba(15,20,30,0.92))',
        border: '1px solid hsl(var(--stroke))',
        position: 'relative',
        overflow: 'hidden',
        display: 'flex',
        flexDirection: 'column',
        scale: cardScale,
        opacity: cardOpacity,
        boxShadow: '0 20px 40px -20px rgba(0,0,0,0.5)',
        willChange: 'transform, opacity',
        transform: 'translateZ(0)',
      }}
    >
      {/* Animated GIF preview at top of card */}
      <div style={{
        position: 'relative',
        width: '100%',
        height: '80%',
        overflow: 'hidden',
        flexShrink: 0,
      }}>
        <img
          src={VIDEO_GIFS[s.num]}
          alt={s.title + ' preview'}
          style={{
            width: '100%',
            height: '100%',
            objectFit: 'cover',
            display: 'block',
          }}
        />
        <div style={{
          position: 'absolute',
          bottom: 0, left: 0, right: 0,
          height: '60%',
          background: 'linear-gradient(to bottom, transparent, rgba(15,20,30,0.95))',
          pointerEvents: 'none',
        }} />
        <div style={{
          position: 'absolute',
          top: '0.75rem', left: '1rem',
          fontFamily: "'Instrument Serif',serif",
          fontSize: '1.2rem',
          color: 'rgba(255,255,255,0.6)',
          letterSpacing: '0.05em',
        }}>{s.num}</div>
      </div>

      <div style={{
        padding: '0.8rem 1.5rem 1rem',
        display: 'flex',
        flexDirection: 'column',
        flex: 1,
      }}>
        <div style={{
          width: 34, height: 34, borderRadius: 10,
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          marginBottom: '0.5rem',
          background: 'linear-gradient(135deg, rgba(137,170,204,0.18), rgba(78,133,191,0.08))',
          border: '1px solid rgba(137,170,204,0.25)',
        }}>
          <span style={{
            background: 'linear-gradient(90deg,var(--accent-from),var(--accent-to))',
            WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent',
            fontSize: '1.1rem',
          }}>{s.icon}</span>
        </div>

        <h3 style={{
          fontFamily: "'Instrument Serif', serif",
          fontSize: '1.3rem', lineHeight: 1.1, margin: 0,
          letterSpacing: '-0.02em',
          color: '#fff',
        }}>{s.title}</h3>

        

        <div style={{
          marginTop: 'auto',
          display: 'flex', flexWrap: 'wrap', gap: '.4rem',
        }}>
          {s.tags.map((t) => (
            <span key={t} style={{
              fontSize: '.65rem',
              padding: '.28rem .65rem',
              borderRadius: 100,
              background: 'rgba(137,170,204,0.1)',
              border: '1px solid rgba(137,170,204,0.15)',
              color: 'var(--accent-from)',
              fontFamily: "'Inter',sans-serif",
              letterSpacing: '.04em',
            }}>{t}</span>
          ))}
        </div>
      </div>

      <div aria-hidden style={{
        position: 'absolute', inset: 0, borderRadius: 28,
        background: 'radial-gradient(600px circle at 20% 0%, rgba(137,170,204,0.08), transparent 50%)',
        pointerEvents: 'none',
      }} />
    </motion.article>
  );
}

function HeadlineWord({ word, i, p }) {
  const start = 0.04 + i * 0.05;
  const wOpacity = useTransform(p, [start, start + 0.08], [0, 1]);
  const wY       = useTransform(p, [start, start + 0.1], ['40%', '0%']);
  const isAccent = word === 'Create';

  return (
    <motion.span
      style={{
        display: 'inline-block',
        marginRight: i < HEADLINE.length - 1 ? '0.25em' : 0,
        opacity: wOpacity,
        y: wY,
        fontStyle: isAccent ? 'italic' : 'normal',
        background: isAccent ? 'linear-gradient(90deg,var(--accent-from),var(--accent-to))' : 'none',
        WebkitBackgroundClip: isAccent ? 'text' : 'border-box',
        WebkitTextFillColor: isAccent ? 'transparent' : 'currentColor',
        willChange: 'transform, opacity',
      }}
    >
      {word}
    </motion.span>
  );
}

export default function Services() {
  const sectionRef = useRef(null);
  const { scrollYProgress } = useScroll({
    target: sectionRef,
    offset: ['start start', 'end end'],
  });

  const p = useSpring(scrollYProgress, { stiffness: 90, damping: 24, mass: 0.4 });

  const headlineScale   = useTransform(p, [0, 0.18, 0.35], [0.8, 1, 1.05]);
  const headlineOpacity = useTransform(p, [0, 0.08, 0.28, 0.38], [0, 1, 1, 0]);
  const headlineY       = useTransform(p, [0, 0.35], ['0vh', '-10vh']);
  const bgGridY         = useTransform(p, [0, 1], ['0%', '-20%']);
  const railX           = useTransform(p, [0.35, 0.95], ['12vw', '-78vw']);
  const railOpacity     = useTransform(p, [0.30, 0.40, 0.92, 0.98], [0, 1, 1, 0.3]);
  const barScale        = useTransform(p, [0, 1], [0, 1]);

  const countMV = useTransform(p, [0.30, 0.95], [0, services.length]);
  const countDisplay = useMotionValue('00');
  useMotionValueEvent(countMV, 'change', (v) => {
    const n = Math.min(services.length, Math.max(0, Math.round(v)));
    countDisplay.set(String(n).padStart(2, '0'));
  });

  const scrollHintOpacity = useTransform(p, [0, 0.1, 0.25], [1, 1, 0]);

  return (
    <section
      id="services"
      ref={sectionRef}
      style={{ position: 'relative', height: '480vh', background: 'hsl(var(--bg))' }}
    >
      <div style={{
        position: 'sticky', top: 0, height: '100vh',
        overflow: 'hidden', width: '100%', transform: 'translateZ(0)',
      }}>
        <motion.div aria-hidden style={{
          position: 'absolute', inset: 0,
          backgroundImage:
            'linear-gradient(rgba(137,170,204,0.06) 1px, transparent 1px),' +
            'linear-gradient(90deg, rgba(137,170,204,0.06) 1px, transparent 1px)',
          backgroundSize: '60px 60px',
          y: bgGridY,
          maskImage: 'radial-gradient(ellipse at center, black 35%, transparent 75%)',
          WebkitMaskImage: 'radial-gradient(ellipse at center, black 35%, transparent 75%)',
          willChange: 'transform',
        }} />
        <div aria-hidden style={{
          position: 'absolute',
          width: '70vmax', height: '70vmax', borderRadius: '50%',
          top: '-25vmax', left: '-10vmax',
          background: 'radial-gradient(circle, rgba(78,133,191,0.18), rgba(78,133,191,0) 60%)',
          pointerEvents: 'none',
        }} />
        <div aria-hidden style={{
          position: 'absolute',
          width: '55vmax', height: '55vmax', borderRadius: '50%',
          bottom: '-18vmax', right: '-10vmax',
          background: 'radial-gradient(circle, rgba(137,170,204,0.14), rgba(137,170,204,0) 60%)',
          pointerEvents: 'none',
        }} />

        <motion.div style={{
          position: 'absolute', top: '12vh', left: 0, right: 0,
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          gap: '1rem', opacity: headlineOpacity,
        }}>
          <div style={{ width: 32, height: 1, background: 'hsl(var(--stroke))' }} />
          <span style={{
            fontSize: '.72rem', color: 'hsl(var(--muted))',
            textTransform: 'uppercase', letterSpacing: '.4em',
            fontFamily: "'Inter',sans-serif",
          }}>Services</span>
          <div style={{ width: 32, height: 1, background: 'hsl(var(--stroke))' }} />
        </motion.div>

        <motion.h2 style={{
          position: 'absolute',
          top: '50%', left: '50%',
          translateX: '-50%', translateY: '-50%',
          y: headlineY, scale: headlineScale, opacity: headlineOpacity,
          margin: 0,
          fontFamily: "'Instrument Serif', serif",
          fontSize: 'clamp(3.5rem, 13vw, 14rem)',
          lineHeight: 0.95, letterSpacing: '-0.04em',
          textAlign: 'center', color: '#fff',
          whiteSpace: 'nowrap', pointerEvents: 'none',
          willChange: 'transform, opacity',
        }}>
          {HEADLINE.map((word, i) => (
            <HeadlineWord key={word} word={word} i={i} p={p} />
          ))}
        </motion.h2>

        <motion.div style={{
          position: 'absolute', top: '12vh', right: '4vw',
          display: 'flex', alignItems: 'baseline', gap: '.4rem',
          opacity: railOpacity,
          fontFamily: "'Instrument Serif', serif",
          color: 'hsl(var(--muted))',
        }}>
          <motion.span style={{
            fontSize: '2.4rem', lineHeight: 1,
            background: 'linear-gradient(90deg,var(--accent-from),var(--accent-to))',
            WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent',
          }}>
            {countDisplay}
          </motion.span>
          <span style={{ fontSize: '1rem', opacity: 0.6 }}>/ {String(services.length).padStart(2,'0')}</span>
        </motion.div>

        <motion.div style={{
          position: 'absolute', top: '50%', left: 0,
          translateY: '-50%', x: railX, opacity: railOpacity,
          display: 'flex', gap: '2rem', padding: '0 4vw',
          willChange: 'transform, opacity',
        }}>
          {services.map((s, i) => (
            <ServiceCard key={s.num} s={s} i={i} p={p} />
          ))}
        </motion.div>

        <div style={{
          position: 'absolute', left: '4vw', right: '4vw', bottom: '5vh',
          height: 2, background: 'rgba(255,255,255,0.06)', borderRadius: 99,
          overflow: 'hidden',
        }}>
          <motion.div style={{
            height: '100%', transformOrigin: '0% 50%', scaleX: barScale,
            background: 'linear-gradient(90deg,var(--accent-from),var(--accent-to))',
          }} />
        </div>

        <motion.div style={{
          position: 'absolute', bottom: '8vh', left: '50%',
          translateX: '-50%',
          fontFamily: "'Inter',sans-serif",
          fontSize: '.7rem', letterSpacing: '.4em',
          color: 'hsl(var(--muted))',
          textTransform: 'uppercase',
          opacity: scrollHintOpacity,
        }}>
          \u2193 Scroll
        </motion.div>
      </div>
    </section>
  );
}
